variables.nginxTemplate:
server {
    proxy_http_version 1.1;
    listen 8080;
    server_name localhost;

    absolute_redirect off;

    location = /favicon.ico {
        return 204;
        access_log off;
    }

    location = /admin {
        return 308 /;
    }

    location ^~ /admin/ {
        rewrite ^/admin/(.*)$ /$1 permanent;
    }

    location = /api {
        return 308 /api/;
    }

    # The backend maps the anonymous Prometheus scraping endpoint at /metrics, which the
    # /api/ proxy below would otherwise surface publicly as /api/metrics. Metrics are for
    # in-environment scrapers reaching the backend directly on its internal ingress, so
    # block the endpoint at the public edge. Return 404 to avoid confirming it exists.
    location = /api/metrics {
        return 404;
    }

    location ^~ /api/ {
        proxy_pass         http://${BACKEND_HOST}/;
        proxy_set_header   Host              ${BACKEND_HOST};
        proxy_set_header   X-Real-IP         $remote_addr;
        proxy_set_header   X-Forwarded-For   $proxy_add_x_forwarded_for;
        proxy_set_header   X-Forwarded-Proto $scheme;
        proxy_read_timeout 120s;
    }

    location / {
        proxy_pass         http://${FRONTEND_HOST};
        proxy_set_header   Host              ${FRONTEND_HOST};
        proxy_set_header   X-Real-IP         $remote_addr;
        proxy_set_header   X-Forwarded-For   $proxy_add_x_forwarded_for;
        proxy_set_header   X-Forwarded-Proto $scheme;
    }
}
